  \draw [>->] (I/s) to node[left] {$ { \mathopen {} \left \langle 1 _{ I } , \top \right \rangle \mathclose {}} $} (IxSigma);
  \draw [->] (IxSigma) to node[upright desc] {$p$} (C);
  \draw [->] (I/n) to node[sloped,above] {$f$} (C);
  \draw [->] (I/s) to node[sloped,below] {$g$} (C);
\end {tikzpicture}

