  \draw [->>] (nw) to node[left] {$ \mathsf { purify } _A$} (sw);
  \draw [>->] (sw) to node[below] {$ \mathsf { L } { \iota ^+}; \alpha _A$} (se);
  \draw [double] (nw) to node[sloped,above] (idn) {$ 1 _{ A } $} (se);
  \node [between = sw and idn] {$ \sqsubseteq $};
\end {tikzpicture}

